svg.script:
document.addEventListener('DOMContentLoaded', () => {
  const svg = document.querySelector('svg');
  if (!svg) return;
  const nodes = Array.from(svg.querySelectorAll('g')).filter(g => g.querySelector('.node-rect'));
  const edges = Array.from(svg.querySelectorAll('.edge-line, .edge-label'));
  nodes.forEach(node => {
    node.style.cursor = 'pointer';
    node.addEventListener('mouseenter', () => {
      const nodeId = node.id;
      nodes.forEach(n => {
        if (n.id !== nodeId) {
          n.style.opacity = '0.15';
          n.style.transition = 'opacity 0.2s ease';
        }
      });
      const connectedNodeIds = new Set([nodeId]);
      edges.forEach(edge => {
        const source = edge.getAttribute('data-source');
        const target = edge.getAttribute('data-target');
        const isConnected = (source === nodeId || target === nodeId || 
                             (source && source.startsWith(nodeId + '.')) || 
                             (target && target.startsWith(nodeId + '.')) ||
                             (nodeId && nodeId.startsWith(source + '.')) ||
                             (nodeId && nodeId.startsWith(target + '.')));
        if (isConnected) {
          if (source) connectedNodeIds.add(source);
          if (target) connectedNodeIds.add(target);
          const dotSrc = source ? source.lastIndexOf('.') : -1;
          if (dotSrc > 0) connectedNodeIds.add(source.substring(0, dotSrc));
          const dotTgt = target ? target.lastIndexOf('.') : -1;
          if (dotTgt > 0) connectedNodeIds.add(target.substring(0, dotTgt));
          edge.style.opacity = '1';
          if (edge.classList.contains('edge-line')) {
            edge.style.strokeWidth = '2.8px';
          }
          edge.style.fontWeight = 'bold';
          edge.style.transition = 'opacity 0.2s ease, stroke-width 0.2s ease';
        } else {
          edge.style.opacity = '0.08';
          edge.style.transition = 'opacity 0.2s ease';
        }
      });
      nodes.forEach(n => {
        if (connectedNodeIds.has(n.id)) {
          n.style.opacity = '1';
        }
      });
    });
    node.addEventListener('mouseleave', () => {
      nodes.forEach(n => {
        n.style.opacity = '1';
      });
      edges.forEach(edge => {
        edge.style.opacity = '1';
        edge.style.strokeWidth = '';
        edge.style.fontWeight = '';
      });
    });
  });
});
